import React, { Fragment } from 'react';
import All_products_Customer from './All_products_Customer'; // Import the All_Products_Customer component
import { Navigate } from 'react-router-dom'; // Import Link for routing

const Home_Customer = ({ setAuth }) => {
  const handleLogout = () => {
    setAuth(false);
  };
  // Redirect to Home when setAuth(false) is called
  if (!isAuthenticated) {
    return <Navigate to="/" />;
  }

  return (
    <Fragment>
      {/* Title Bar */}
      <div className="title-bar">
        <h1>Shohojog</h1>
        <div className="logout-option">
          <button onClick={handleLogout}>Log out</button>
        </div>
      </div>
      <All_products_Customer /> 
    </Fragment>
  );
};

export default Home_Customer;
